import streamlit as st
import pandas as pd
import matplotlib.pyplot as plt
import numpy as np


def plot_chart(df_plot, title):
    fig, ax = plt.subplots(figsize=(10, 9)) 
    y_pos = np.arange(len(df_plot))

    ax.barh(y_pos, df_plot['Đã nhập (cũ)'], 
            color='#06A77D', label='Đã nhập (cũ)', edgecolor='white', linewidth=0.5)

    ax.barh(y_pos, df_plot['Số mới nhập'], 
            left=df_plot['Đã nhập (cũ)'],
            color='#F18F01', label='Số mới nhập', edgecolor='white', linewidth=0.5)

    ax.barh(y_pos, df_plot['Còn lại cần nhập'], 
            left=df_plot['Tổng đã nhập'],
            color='#DC143C', label='Còn lại cần nhập', edgecolor='white', linewidth=0.5)

    ax.set_yticks(y_pos)
    ax.set_yticklabels(df_plot['Tỉnh'], fontsize=9)
    ax.invert_yaxis() 
    ax.set_xlabel('Số lượng', fontsize=10, fontweight='bold')
    ax.set_title(title, fontsize=12, fontweight='bold', pad=15)

    max_val = max(df_plot['Số cần nhập'].max(), df_plot['Tổng đã nhập'].max())
    offset = max_val * 0.02

    for i, (idx, row) in enumerate(df_plot.iterrows()):
        total_req = row['Số cần nhập']
        total_imp = row['Tổng đã nhập']
        percentage = (total_imp / total_req * 100) if total_req > 0 else 0
        actual_end = max(total_req, total_imp)
        
        ax.text(actual_end + offset, i, 
                f"{int(total_imp)}/{int(total_req)} ({percentage:.0f}%)", 
                va='center', ha='left', fontsize=8, fontweight='bold')

    ax.set_xlim(0, max_val * 1.3)
    ax.grid(axis='x', alpha=0.3, linestyle='--')
    ax.legend(loc='lower right', frameon=True, fontsize=9)

    plt.tight_layout()
    st.pyplot(fig)
    return fig

def format_data(df):
    df['Đã nhập (cũ)'] = df['Tổng đã nhập'] - df['Số mới nhập']
    df['Còn lại cần nhập'] =  df['Số cần nhập'] - df['Tổng đã nhập']
    df['Còn lại cần nhập'] = df['Còn lại cần nhập'].apply(lambda x: 0 if x < 0 else x)
    df['Tỷ lệ'] = df.apply(lambda row: row['Tổng đã nhập'] / row['Số cần nhập'] * 100 if row['Số cần nhập'] > 0 else 0, axis=1)
    df = df.sort_values('Tổng đã nhập', ascending=False).reset_index(drop=True)
    return df

def render_html_table(df_table):
    """Tạo bảng HTML với header nền xanh đậm, chữ trắng, zebra striping."""
    cols = ['Tỉnh', 'Số cần nhập', 'Số mới nhập', 'Tổng đã nhập', 'Tỷ lệ']

    header_cells = '<th style="background:#1a3a5c;color:#fff;font-weight:bold;padding:8px 10px;text-align:center;border-bottom:2px solid #F18F01;white-space:nowrap;">STT</th>'
    for col in cols:
        align = 'left' if col == 'Tỉnh' else 'center'
        header_cells += f'<th style="background:#1a3a5c;color:#fff;font-weight:bold;padding:8px 10px;text-align:{align};border-bottom:2px solid #F18F01;white-space:nowrap;">{col}</th>'

    rows_html = ''
    for i, (_, row) in enumerate(df_table.iterrows()):
        bg = '#f0f5fb' if i % 2 == 0 else '#ffffff'
        stt = i + 1
        ty_le = f"{row['Tỷ lệ']:.1f}%"
        row_cells = f'<td style="padding:6px 10px;text-align:center;color:#333;">{stt}</td>'
        for col in cols:
            align = 'left' if col == 'Tỉnh' else 'center'
            val = ty_le if col == 'Tỷ lệ' else row[col]
            row_cells += f'<td style="padding:6px 10px;text-align:{align};color:#333;">{val}</td>'
        rows_html += f'<tr style="background:{bg};">{row_cells}</tr>'

    html = f"""
    <div style="overflow-y:auto; max-height:700px; border:1px solid #ddd; border-radius:6px;">
      <table style="width:100%; border-collapse:collapse; font-size:13px; font-family:sans-serif;">
        <thead style="position:sticky;top:0;z-index:1;">
          <tr>{header_cells}</tr>
        </thead>
        <tbody>{rows_html}</tbody>
      </table>
    </div>
    """
    st.markdown(html, unsafe_allow_html=True)

def hienthidulieu(df, title):
    df = format_data(df)
    df_sorted = df.sort_values('Tổng đã nhập', ascending=False)
    
    col1, col2 = st.columns([1, 1.5])

    with col1:
        df_table = df_sorted.copy()
        df_table = df_table.sort_values('Tổng đã nhập', ascending=False).reset_index(drop=True)
        render_html_table(df_table)

    with col2:
        df_plot = df_sorted.sort_values('Tổng đã nhập', ascending=False).reset_index(drop=True)
        if len(df_plot) > 40:
            df_plot = df_plot.head(40)
        plot_chart(df_plot, title)


